def read_debt_list_from_csv():
  access_token = get_access_token()
  file_path_info = find_file_path(
    file_name="owe_list.csv", access_token=access_token
  )
  file_content = file_system.show_file(
    file_path=file_path_info["primary"],
    access_token=access_token["primary"],
  )
  raw_content = file_content["content"]
  lines = raw_content.strip().split("\n")
  if not lines:
    return {
      "primary": [],
      "extras": {
        "file_path": file_path_info["primary"],
        "file_id": file_content.get("file_id"),
        "created_at": file_content.get("created_at"),
        "updated_at": file_content.get("updated_at"),
      }
    }
  data_lines = lines[1:]
  result = []
  for line in data_lines:
    parts = line.split(",")
    if len(parts) >= 4:
      name = parts[0]
      email = parts[1]
      amount_str = parts[2]
      description = parts[3]
      amount = float(amount_str.replace("$", ""))
      result.append(
        {
          "name": name,
          "email": email,
          "amount": amount,
          "description": description,
        }
      )

  return {
    "primary": result,
    "extras": {
      "file_path": file_path_info["primary"],
      "file_id": file_content.get("file_id"),
      "created_at": file_content.get("created_at"),
      "updated_at": file_content.get("updated_at"),
      "total_entries": len(result),
    }
  }
